from collections import deque

def level_order(root):
    if not root: return
    q = deque([root])
    while q:
        n = q.popleft()
        yield n.key
        if n.left:  q.append(n.left)
        if n.right: q.append(n.right)

print(list(level_order(root)))   # [4, 2, 6, 1, 3, 5, 7]
